import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import response from './response.json';

interface GoalData {
  goal: {
    name: string;
    targetAmount: number;
    currentAmount: number;
    progressPercentage: number;
    projectedCompletionDate: string;
  };
}

export default function Widget() {
  const data = response.data as GoalData;
  const { goal } = data;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2.5}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#4CAF50' }}>
              {goal.name}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              ${goal.currentAmount.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              of ${goal.targetAmount.toLocaleString()} goal
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: '#4CAF50' }}>
                {goal.progressPercentage}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={goal.progressPercentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#E8F5E9',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#4CAF50',
                  borderRadius: 4,
                }
              }}
            />
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Projected Completion Date
            </Typography>
            <Typography variant="body1" fontWeight={500} sx={{ color: '#FFC107' }}>
              {new Date(goal.projectedCompletionDate).toLocaleDateString()}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
